        </div>
    </div>

    <script>
        // Buggy Version
        let buggyCount = 0;
        const buggyCountElement = document.getElementById('buggy-count');
        const buggyButton = document.getElementById('buggy-button');

        buggyButton.addEventListener('click', () => {
            setTimeout(() => {
                buggyCount++;
                buggyCountElement.textContent = `Count: ${buggyCount}`;
            }, 0);
        });

        // Corrected Version
        const correctedCountElement = document.getElementById('corrected-count');
        const correctedButton = document.getElementById('corrected-button');

        correctedButton.addEventListener('click', () => {
            correctedCountElement.textContent = `Count: ${parseInt(correctedCountElement.textContent.split(': ')[1]) + 1}`;
        });
    </script>
</body>
</html>
